import { Component, OnDestroy, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import {
  ActivatedRoute,
  NavigationEnd,
  Router,
  RouterOutlet,
} from '@angular/router';
import { Subscription, filter } from 'rxjs';
import { Step, TaxReturn } from '../../core/models';

interface StepDef {
  slug: string;
  step: Step;
  label: string;
}

/**
 * Wizard shell: loads the return, renders the stepper reflecting `currentStep`,
 * and hosts the step <router-outlet>. On entry (landing on the bare
 * /returns/:id/wizard URL) it redirects to the DB `currentStep` so a resumed
 * draft lands on the saved step — state comes from the return, not memory.
 */
@Component({
  selector: 'app-wizard-shell',
  standalone: true,
  imports: [CommonModule, RouterOutlet],
  templateUrl: './wizard-shell.component.html',
  styleUrl: './wizard-shell.component.css',
})
export class WizardShellComponent implements OnInit, OnDestroy {
  readonly steps: StepDef[] = [
    { slug: 'filing-status', step: 'filing_status', label: 'Filing status' },
    { slug: 'dependents', step: 'dependents', label: 'Dependents' },
    { slug: 'income', step: 'income', label: 'Income' },
    { slug: 'deductions', step: 'deductions', label: 'Deductions' },
    { slug: 'review', step: 'review', label: 'Review' },
  ];

  returnId = '';
  activeSlug = signal<string>('filing-status');

  // Mock return — service_agent clears this and loads it from ApiService.getReturn().
  taxReturn = signal<TaxReturn | null>({
    id: 'r-2024',
    userId: 'me',
    year: 2024,
    filingStatus: 'single',
    currentStep: 'income',
    status: 'draft',
  });

  private sub?: Subscription;

  constructor(private route: ActivatedRoute, private router: Router) {}

  ngOnInit(): void {
    this.returnId = this.route.snapshot.paramMap.get('id') ?? '';

    // Redirect a bare wizard URL to the saved step.
    const child = this.route.snapshot.firstChild;
    if (!child) {
      const saved = this.taxReturn()?.currentStep ?? 'filing_status';
      const slug = this.steps.find((s) => s.step === saved)?.slug ?? 'filing-status';
      this.router.navigate([slug], { relativeTo: this.route, replaceUrl: true });
    }

    this.syncActive(this.router.url);
    this.sub = this.router.events
      .pipe(filter((e): e is NavigationEnd => e instanceof NavigationEnd))
      .subscribe((e) => this.syncActive(e.urlAfterRedirects));
  }

  ngOnDestroy(): void {
    this.sub?.unsubscribe();
  }

  private syncActive(url: string): void {
    const match = this.steps.find((s) => url.includes('/wizard/' + s.slug));
    if (match) this.activeSlug.set(match.slug);
  }

  activeIndex(): number {
    return Math.max(0, this.steps.findIndex((s) => s.slug === this.activeSlug()));
  }

  goTo(slug: string): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', slug]);
  }

  exit(): void {
    this.router.navigate(['/returns']);
  }
}
